IGPersist.capture={init:function(t){if(!IGPersist.state.captureInit[t]){IGPersist.state.captureInit[t]=!0;var e=IGPersist.config.selectors,s=IGPersist.core.getGridBase(t);document.addEventListener("click",(function(i){i.target.closest(s+" "+e.pagination+" "+e.button)&&setTimeout((function(){var i=$(s+" "+e.selected);if(i.length){var r=i.attr(IGPersist.config.attributes.page);if(r){var a=IGPersist.core.getPageKey(t);IGPersist.storage.save(a,r)}}}),IGPersist.config.timing.waitClick)}),!0)}},_setPage:function(t){var e=IGPersist.config.selectors,s=IGPersist.core.getGridBase(t),i=$(s+" "+e.selected);if(i.length){var r=i.attr(IGPersist.config.attributes.page);if(r){var a=IGPersist.core.getPageKey(t);IGPersist.storage.save(a,r)}}}};